     1→import type { PageLoad } from './$types';
     2→import type { Container } from '$lib/types/container.js';
     3→
     4→export interface ContainerPageData {
     5→	container: Container | null;
     6→	error: string | null;
     7→}
     8→
     9→export async function _load(id: string, fetchFn: typeof fetch): Promise<ContainerPageData> {
    10→	try {
    11→		const res = await fetchFn(`/api/containers/${id}`);
    12→		if (res.status === 404) {
    13→			return { container: null, error: `Container '${id}' not found` };
    14→		}
    15→		if (!res.ok) {
    16→			return { container: null, error: `Failed to load container (${res.status})` };
    17→		}
    18→		const container: Container = await res.json();
    19→		return { container, error: null };
    20→	} catch {
    21→		return { container: null, error: 'Network error loading container' };
    22→	}
    23→}
    24→
    25→export const load: PageLoad = async ({ params, fetch }) => {
    26→	return _load(params.id, fetch);
    27→};
