     3→import { validateContainerName, validateRequired } from '$lib/server/validation.js';
     4→import { ContainerService } from '$lib/server/containers/container-service.js';
     5→import type { ContainerConfig } from '$lib/types/container.js';
     6→
     7→// Exported for testing (underscore prefix required by SvelteKit for custom route exports)
     8→export async function _handleGetContainers(service: ContainerService): Promise<Response> {
     9→	const containers = await service.list();
    10→	return jsonResponse(containers);
    11→}
    12→
    13→interface CreateContainerBody {
    14→	name?: unknown;
    15→	templateId?: unknown;
    16→	config?: unknown;
    17→}
    18→
    19→export async function _handlePostContainer(
    20→	request: Request,
    21→	service: ContainerService
    22→): Promise<Response> {
    23→	let body: CreateContainerBody;
    24→	try {
    25→		body = await parseRequestBody<CreateContainerBody>(request);
    26→	} catch {
    27→		return errorResponse('Request body is required', 400);
    28→	}
    29→
    30→	if (typeof body.name !== 'string') {
    31→		return errorResponse('name is required and must be a string', 400);
    32→	}
    33→	if (typeof body.templateId !== 'string') {
    34→		return errorResponse('templateId is required and must be a string', 400);
    35→	}
    36→
    37→	const nameValidation = validateContainerName(body.name);
    38→	if (!nameValidation.success) {
    39→		return errorResponse(nameValidation.error, 400);
    40→	}
    41→
    42→	const templateValidation = validateRequired(body.templateId, 'templateId');
    43→	if (!templateValidation.success) {
    44→		return errorResponse(templateValidation.error, 400);
    45→	}
    46→
    47→	const config = (body.config ?? {}) as ContainerConfig;
    48→
    49→	try {
    50→		const container = await service.create({
    51→			name: body.name,
    52→			templateId: body.templateId,
    53→			config
    54→		});
    55→		return jsonResponse(container, 201);
    56→	} catch (err) {
    57→		const message = err instanceof Error ? err.message : 'Failed to create container';
    58→		if (message.includes('already exists')) {
    59→			return errorResponse(`Container name '${body.name}' is already taken`, 409);
    60→		}
    61→		return errorResponse(message, 500);
    62→	}
    63→}
    64→
    65→export const GET: RequestHandler = async () => {
    66→	const { getContainerService } = await import('$lib/server/containers/singleton.js');
    67→	return _handleGetContainers(getContainerService());
    68→};
    69→
    70→export const POST: RequestHandler = async ({ request }) => {
    71→	const { getContainerService } = await import('$lib/server/containers/singleton.js');
    72→	return _handlePostContainer(request, getContainerService());
    73→};
