// --- New container modal ---
function NewContainerModal({ open, onClose }) {
  const [selected, setSelected] = useState("tmpl-rust");
  const [step, setStep] = useState(0);
  const [name, setName] = useState("");
  const [repo, setRepo] = useState("");
  const tmpl = CONTAINER_TEMPLATES.find((t) => t.id === selected);

  if (!open) return null;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        backgroundColor: "rgba(0,0,0,0.6)",
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "center",
        zIndex: 100,
      }}
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          backgroundColor: p.surface,
          borderRadius: "16px 16px 0 0",
          width: "100%",
          maxWidth: 480,
          padding: 24,
          border: `1px solid ${p.border}`,
          borderBottom: "none",
          maxHeight: "85vh",
          overflowY: "auto",
        }}
      >
        {step === 0 ? (
          <>
            <h3
              style={{
                fontFamily: f.sans,
                fontSize: 16,
                fontWeight: 600,
                color: p.text,
                margin: "0 0 4px",
              }}
            >
              New Container
            </h3>
            <p
              style={{
                fontFamily: f.sans,
                fontSize: 13,
                color: p.textDim,
                margin: "0 0 16px",
              }}
            >
              Choose a template to start from
            </p>
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                gap: 8,
              }}
            >
              {CONTAINER_TEMPLATES.map((tmpl) => (
                <button
                  key={tmpl.id}
                  onClick={() => setSelected(tmpl.id)}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 12,
                    padding: "14px 16px",
                    borderRadius: 10,
                    cursor: "pointer",
                    textAlign: "left",
                    backgroundColor:
                      selected === tmpl.id
                        ? p.accentBg
                        : p.surfaceRaised,
                    border: `1px solid ${selected === tmpl.id ? p.accentDim : p.border}`,
                    transition: "all 0.15s",
                  }}
                >
                  <span
                    style={{
                      fontSize: 18,
                      width: 32,
                      textAlign: "center",
                    }}
                  >
                    {tmpl.icon}
                  </span>
                  <div>
                    <div
                      style={{
                        fontFamily: f.sans,
                        fontSize: 14,
                        fontWeight: 600,
                        color:
                          selected === tmpl.id ? p.accent : p.text,
                      }}
                    >
                      {tmpl.name}
                    </div>
                    <div
                      style={{
                        fontFamily: f.sans,
                        fontSize: 12,
                        color: p.textDim,
                        marginTop: 2,
                      }}
                    >
                      {tmpl.description}
                    </div>
                  </div>
                </button>
              ))}
            </div>
            <button
              onClick={() => setStep(1)}
              style={{
                width: "100%",
                marginTop: 16,
                padding: "12px 0",
                borderRadius: 10,
                backgroundColor: p.accent,
                border: "none",
                color: p.bg,
                fontFamily: f.sans,
                fontSize: 14,
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              Continue
            </button>
          </>
        ) : (
          <>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                marginBottom: 16,
              }}
            >
              <IconBtn onClick={() => setStep(0)}>←</IconBtn>
              <h3
                style={{
                  fontFamily: f.sans,
                  fontSize: 16,
                  fontWeight: 600,
                  color: p.text,
                  margin: 0,
                }}
              >
                Configure
              </h3>
              <Pill color={p.accent} bg={p.accentBg}>
                {tmpl?.name}
              </Pill>
            </div>
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                gap: 14,
              }}
            >
              <label
                style={{
                  fontFamily: f.sans,
                  fontSize: 12,
                  color: p.textMuted,
                }}
              >
                Container Name
                <input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="my-project"
                  style={{
                    display: "block",
                    width: "100%",
                    marginTop: 6,
                    padding: "10px 12px",
                    backgroundColor: p.surfaceRaised,
                    border: `1px solid ${p.border}`,
                    borderRadius: 8,
                    color: p.text,
                    fontFamily: f.mono,
                    fontSize: 13,
                    outline: "none",
                    boxSizing: "border-box",
                  }}

                />
              </label>
              <label
                style={{
                  fontFamily: f.sans,
                  fontSize: 12,
                  color: p.textMuted,
                }}
              >
                Git Repository
                <input
                  value={repo}
                  onChange={(e) => setRepo(e.target.value)}
                  placeholder="git@github.com:user/repo.git or blank for new"
                  style={{
                    display: "block",
                    width: "100%",
                    marginTop: 6,
                    padding: "10px 12px",
                    backgroundColor: p.surfaceRaised,
                    border: `1px solid ${p.border}`,
                    borderRadius: 8,
                    color: p.text,
                    fontFamily: f.mono,
                    fontSize: 13,
                    outline: "none",
                    boxSizing: "border-box",
                  }}
                />
              </label>
              <label
                style={{
                  fontFamily: f.sans,
                  fontSize: 12,
                  color: p.textMuted,
                }}
              >
                CLAUDE.md
                <div
                  style={{
                    display: "flex",
                    gap: 8,
                    marginTop: 6,
                  }}
                >
                  {["From repo", "From template", "None"].map(
                    (opt) => (
                      <button
                        key={opt}
                        style={{
                          flex: 1,
                          padding: "9px 0",
                          borderRadius: 8,
                          backgroundColor:
                            opt === "From repo"
                              ? p.blueBg
                              : p.surfaceRaised,
                          border: `1px solid ${opt === "From repo" ? p.blueDim : p.border}`,
                          color:
                            opt === "From repo"
                              ? p.blue
                              : p.textMuted,
                          fontFamily: f.sans,
                          fontSize: 12,
                          fontWeight: 500,
                          cursor: "pointer",
                        }}
                      >
                        {opt}
                      </button>
                    )
                  )}
                </div>
              </label>
              <label
                style={{
                  fontFamily: f.sans,
                  fontSize: 12,
                  color: p.textMuted,
                }}
              >
                VS Code Extensions (additional)
                <input
                  placeholder="ext1, ext2, ..."
                  style={{
                    display: "block",
                    width: "100%",
                    marginTop: 6,
                    padding: "10px 12px",
                    backgroundColor: p.surfaceRaised,
                    border: `1px solid ${p.border}`,
                    borderRadius: 8,
                    color: p.text,
                    fontFamily: f.mono,
                    fontSize: 13,
                    outline: "none",
                    boxSizing: "border-box",
                  }}
                />
              </label>
              <label
                style={{
                  fontFamily: f.sans,
                  fontSize: 12,
                  color: p.textMuted,
                }}
              >
                Post-Create Command (additional)
                <input
                  placeholder="pip install my-lib && ..."
                  style={{
                    display: "block",
                    width: "100%",
                    marginTop: 6,
                    padding: "10px 12px",
                    backgroundColor: p.surfaceRaised,
                    border: `1px solid ${p.border}`,
                    borderRadius: 8,
                    color: p.text,
                    fontFamily: f.mono,
                    fontSize: 13,
                    outline: "none",
                    boxSizing: "border-box",
                  }}
                />
              </label>
              <button
                style={{
                  width: "100%",
                  marginTop: 4,
                  padding: "12px 0",
                  borderRadius: 10,
                  backgroundColor: p.accent,
                  border: "none",
                  color: p.bg,
                  fontFamily: f.sans,
                  fontSize: 14,
                  fontWeight: 600,
                  cursor: "pointer",
                }}
              >
                Create & Launch
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

