import { test, expect } from '@playwright/test';

test('home page loads', async ({ page }) => {
	await page.goto('/');
	await expect(page).toHaveTitle(/HALO/);
});

test('home page displays app name', async ({ page }) => {
	await page.goto('/');
	await expect(page.locator('h1')).toHaveText('HALO');
});

