    82→export type ValidationResult = { success: true } | { success: false; error: string };
    83→
    84→export function validateTemplate(template: Template): ValidationResult {
    85→	if (!template.id) {
    86→		return { success: false, error: 'Template id is required' };
    87→	}
    88→	if (!template.name) {
    89→		return { success: false, error: 'Template name is required' };
